#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=5e5+5;
int n,m,ans=0,anss;
struct node
{
    int x,l;
}a[MAXN];
priority_queue<int> q;
bool cmp(node a,node b){return a.x+a.l<b.x+b.l;}
signed main(void)
{

    //freopen(".in","r",stdin);
    //freopen(".out","w",stdout);
	ios::sync_with_stdio(0);
	cin.tie(0);
	cin>>n;
	FOR(i,1,n)
	{
		cin>>a[i].x;
	}
    FOR(i,1,n)
    {
        cin>>a[i].l;
    }
	sort(a+1,a+n+1,cmp);
	FOR(i,1,n)
	{
		if(m<=a[i].l)
		{
			m+=a[i].x;
			q.push(a[i].x);
		}
		else if(!q.empty())
		{
			int t=q.top();
			if(a[i].x<t)
			{
				q.pop();
				m+=a[i].x-t;
				q.push(a[i].x);
			}
		}
	}
	cout<<q.size();
    return false;
}
